layui.use(["form","layer"],function(){let form=layui.form;let layer=layui.layer;$.ajax({url:"/link_type",method:"GET",dataType:"json",success:function(a){if(a.request==="success"&&a.status===200){$.each(a.data,function(b,c){$("#type").append(new Option(c.name,c.name))});form.render()}},error:function(a){if(a){layer.msg(a)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});form.verify({name:function(b,a){let nameRex=/^[\w\W\s\u4e00-\u9fcc]{2,20}$/;if(!nameRex.test(b)){return"链接名只能为2-20个字符"}}});form.on("submit(form-link-submit)",function(a){let link=a.field;layer.confirm("确认提交？",{btn:["确认","取消"]},function(b){$.ajax({url:"/link",data:{url:link.url,name:link.name,type:link.type},method:"POST",dateType:"json",success:function(c){if(c.request==="success"&&c.status===200){layer.msg(c.message,{icon:1})}else{layer.msg(c.message+", 错误码: "+c.status,{icon:2})}},error:function(c){if(c){layer.msg(c)}else{layer.msg("请求错误，请检查网络",{icon:2})}}});layer.close(b)});return false})});